const input = $input.first().json;
const body = input.body || input;
const text = JSON.stringify(body);

const patterns = [
  { regex: /\b\d{13}\b/g, label: '[REDACTED_SA_ID]' },
  { regex: /\b\d{6,17}\b(?=.*bank)/gi, label: '[REDACTED_BANK_ACCOUNT]' },
  { regex: /[A-Za-z0-9._%+\-]+@[A-Za-z0-9.\-]+\.[A-Za-z]{2,}/g, label: '[REDACTED_EMAIL]' },
  { regex: /(?:\+27|0)[6-8]\d{8}/g, label: '[REDACTED_SA_PHONE]' },
  { regex: /\b[A-Z]{1}\d{7}\b/g, label: '[REDACTED_PASSPORT]' },
  { regex: /\b[A-Z]{2}\d{2}[A-Z0-9]{4,}\d{7,}[A-Z0-9]{0,3}\b/g, label: '[REDACTED_IBAN]' },
  { regex: /\b[A-Z]{6}[A-Z0-9]{2}([A-Z0-9]{3})?\b/g, label: '[REDACTED_SWIFT]' },
  { regex: /\b(?:\d[ -]*?){13,19}\b/g, label: '[REDACTED_CREDIT_CARD]' },
  { regex: /\b(0x[a-fA-F0-9]{40}|[13][a-km-zA-HJ-NP-Z1-9]{25,34}|r[0-9a-zA-Z]{24,34}|T[A-Za-z1-9]{33})\b/g, label: '[REDACTED_CRYPTO_WALLET]' },
  { regex: /(?:sk[_-]live[_-][A-Za-z0-9]{20,}|Bearer\s+[A-Za-z0-9._\-]{20,}|api[_-]?key[=:]\s*[A-Za-z0-9._\-]{16,})/gi, label: '[REDACTED_API_KEY]' }
];

let sanitized = text;
for (const p of patterns) {
  sanitized = sanitized.replace(p.regex, p.label);
}

const sanitizedBody = JSON.parse(sanitized);
return [{ json: { ...input, body: sanitizedBody, _sanitized: true } }];

const crypto = require('crypto');
const input = $input.first().json;
const headers = input.headers || {};
const signature = headers['x-signature'] || '';
const secret = '={{ $env.WEBHOOK_HMAC_SECRET || $env.SUPABASE_SERVICE_ROLE_KEY }}';
const payload = JSON.stringify(input.body || {});

const expected = crypto
  .createHmac('sha256', secret)
  .update(payload)
  .digest('hex');

if (signature !== expected) {
  throw new Error('Invalid HMAC-SHA256 signature');
}

return [{ json: { ...input, _signatureValid: true } }];

const input = $input.first().json;
const documents = Array.isArray(input) ? input : (input.documents || input.results || [input]);

const sorted = documents
  .filter(d => d && typeof d.rerank_score === 'number')
  .sort((a, b) => b.rerank_score - a.rerank_score)
  .slice(0, 5);

return [{ json: { top_memories: sorted } }];

// ═══════════════════════════════════════════════════════════════════════════
// NODE 9: EVAL GATE — Semantic Cosine Similarity (threshold 0.72)
// Replaces hardcoded 0.8/0.7 defaults with real embedding-based evaluation.
// ═══════════════════════════════════════════════════════════════════════════

const input       = $input.first().json;
const llmResponse = input.response || input.text || JSON.stringify(input);
const query       = $('Sig Validator').item.json.body?.query
                 || $('Sig Validator').item.json.body?.text
                 || '';

const THRESHOLD  = 0.72;
const ollamaBase = $env.OLLAMA_BASE_URL || 'https://api.ollama.com';
const ollamaKey  = $env.OLLAMA_API_KEY  || '';
const embedModel = 'nomic-embed-text';   // 768-dim, compatible with pgvector schema

// ─── Cosine similarity ────────────────────────────────────────────────────
function cosine(a, b) {
  if (!a || !b || a.length !== b.length) return 0;
  let dot = 0, magA = 0, magB = 0;
  for (let i = 0; i < a.length; i++) {
    dot  += a[i] * b[i];
    magA += a[i] * a[i];
    magB += b[i] * b[i];
  }
  const denom = Math.sqrt(magA) * Math.sqrt(magB);
  return denom ? dot / denom : 0;
}

// ─── Keyword fallback (used when Ollama embeddings API is unavailable) ────
function keywordSim(q, r) {
  // FIX (CR): coerce to string, use Set for rWords to prevent duplicate counting
  const qStr = String(q || '').toLowerCase().replace(/[^\w\s]/g, ' ');
  const rStr = String(r || '').toLowerCase().replace(/[^\w\s]/g, ' ');
  const qWords = new Set(qStr.split(/\s+/).filter(w => w.length > 3));
  const rSet   = new Set(rStr.split(/\s+/).filter(Boolean));
  if (!qWords.size) return 0; // fail-closed: no query tokens
  // Intersection size — each query token counted once regardless of repetition
  const overlap = [...qWords].filter(w => rSet.has(w)).length;
  return Math.min(0.95, 0.45 + (overlap / qWords.size) * 0.55);
}

// ─── Main eval logic ──────────────────────────────────────────────────────
let similarity     = 0;
let method         = 'keyword_fallback';
let responseEmbed  = null;

if (ollamaBase && query && llmResponse) {
  try {
    const truncResponse = llmResponse.substring(0, 2000);

    // Call Ollama embeddings API for both query and response in parallel
    const [qRes, rRes] = await Promise.all([
      $helpers.httpRequest({
        method:  'POST',
        url:     `${ollamaBase}/api/embeddings`,
        headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${ollamaKey}` },
        body:    JSON.stringify({ model: embedModel, prompt: query }),
        json:    true,
      }),
      $helpers.httpRequest({
        method:  'POST',
        url:     `${ollamaBase}/api/embeddings`,
        headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${ollamaKey}` },
        body:    JSON.stringify({ model: embedModel, prompt: truncResponse }),
        json:    true,
      }),
    ]);

    if (Array.isArray(qRes?.embedding) && Array.isArray(rRes?.embedding)) {
      similarity    = cosine(qRes.embedding, rRes.embedding);
      responseEmbed = rRes.embedding;
      method        = 'cosine_similarity';
    } else {
      similarity = keywordSim(query, llmResponse);
    }

  } catch (_embErr) {
    // Embeddings endpoint unavailable — use keyword fallback
    similarity = keywordSim(query, llmResponse);
  }

} else {
  // No Ollama configured or empty inputs — keyword fallback
  similarity = query ? keywordSim(query, llmResponse) : 0;
}

const passed = similarity >= THRESHOLD;

return [{
  json: {
    eval_passed:        passed,
    semantic_similarity: parseFloat(similarity.toFixed(4)),
    threshold:          THRESHOLD,
    method,
    // response_embedding passed downstream to Memory Store for pgvector write
    response_embedding: passed ? responseEmbed : null,  // FIX: only store embedding when eval passed
    answer: passed
      ? llmResponse
      : 'I was unable to generate a sufficiently relevant answer. Please rephrase your query or provide more context.',
    fallback:          !passed,
    original_response: input,
  }
}];

const evalResult = $('Eval Gate').item.json;
const task = $('Sig Validator').item.json.body.task || '';
const modelMap = {'review':'qwen3.5:397b','security':'qwen3.5:397b','decision':'deepseek-v3.2','plan':'deepseek-v3.2','code':'glm-5','fix':'glm-5','financial':'kimi-k2.5','payment':'kimi-k2.5'};
const modelUsed = modelMap[task] || 'deepseek-v3.2';
const memories = $('Top-5 Filter').item.json.top_memories || [];

const response = {
  success: evalResult.eval_passed,
  answer: evalResult.answer,
  model: modelUsed,
  score: {
    semantic_similarity: evalResult.semantic_similarity
  },
  method: evalResult.method || 'unknown',
  memories_used: memories.length,
  memory_ids: memories.map(m => m.id).filter(Boolean),
  fallback: evalResult.fallback || false,
  timestamp: new Date().toISOString()
};

return [{ json: response }];
